@using sv_55ff59d73279411b9ce84f971a22095f

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list">
            @if (HasMoreMessages)
            {
                <div class="load-more">
                    <button class="load-more-btn" @onclick="OnLoadMore" disabled="@IsLoading">
                        @(IsLoading ? "Loading..." : "Load older messages")
                    </button>
                </div>
            }

            @if (Messages is not null)
            {
                @foreach (var msg in Messages)
                {
                    var summary = ThreadSummaries?.GetValueOrDefault(msg.Id);
                    <MessageItem Message="msg"
                                 ThreadSummary="summary"
                                 OnReplyClicked="() => OnThreadOpen.InvokeAsync(msg.Id)"
                                 OnReactionAdded="(emoji) => OnReactionAdded.InvokeAsync((msg.Id, emoji))" />
                }
            }
        </div>

        <div class="message-input-area">
            <textarea class="message-textarea"
                      @bind="newMessageText"
                      @bind:event="oninput"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="HandleSend" disabled="@(string.IsNullOrWhiteSpace(newMessageText))">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
