@@ -1,0 +1,87 @@
+@using sv_55ff59d73279411b9ce84f971a22095f
+
+<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="OnMouseLeave">
+    <div class="message-header">
+        <span class="message-author">@Message.Author</span>
+        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
+    </div>
+    <div class="message-content">@Message.Content</div>
+
+    @if (Message.Reactions.Count > 0)
+    {
+        <div class="message-reactions">
+            @foreach (var reaction in Message.Reactions)
+            {
+                <span class="reaction-badge">@reaction.Emoji @reaction.Users.Count</span>
+            }
+        </div>
+    }
+
+    @if (ThreadSummary is not null)
+    {
+        <div class="thread-link" @onclick="OnReplyClicked">
+            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
+        </div>
+    }
+
+    @if (_showActions)
+    {
+        <div class="message-actions">
+            <button class="action-btn" @onclick="OnReplyClicked">💬 Reply</button>
+            <div class="react-wrapper">
+                <button class="action-btn" @onclick="ToggleEmojiPicker" @onclick:stopPropagation="true">😀 React</button>
+                @if (_showEmojiPicker)
+                {
+                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
+                }
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
+    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
+    [Parameter] public EventCallback OnReplyClicked { get; set; }
+    [Parameter] public EventCallback<string> OnReactionAdded { get; set; }
+
+    private bool _showActions;
+    private bool _showEmojiPicker;
+
+    private void OnMouseLeave()
+    {
+        _showActions = false;
+        _showEmojiPicker = false;
+    }
+
+    private void ToggleEmojiPicker()
+    {
+        _showEmojiPicker = !_showEmojiPicker;
+    }
+
+    private async Task HandleEmojiSelected(string emoji)
+    {
+        _showEmojiPicker = false;
+        await OnReactionAdded.InvokeAsync(emoji);
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt;
+
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 60)
+        {
+            var mins = (int)diff.TotalMinutes;
+            return $"{mins} min ago";
+        }
+        if (diff.TotalHours < 24)
+        {
+            var hrs = (int)diff.TotalHours;
+            return $"{hrs} hr ago";
+        }
+        if (diff.TotalHours < 48) return "Yesterday";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+}
+

