@page "/chat"
@rendermode InteractiveServer
@using sv_55ff59d73279411b9ce84f971a22095f
@using sv_55ff59d73279411b9ce84f971a22095f.Components.Chat
@inject IChatService ChatService

<div class="chat-page @(openThreadRootId.HasValue ? "thread-open" : "")">
    <div class="sidebar">
        <ChannelList Channels="channels"
                     ActiveChannelId="activeChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>
    <div class="main">
        <MessageArea Channel="activeChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoading="isLoading"
                     HasMoreMessages="hasMoreMessages"
                     OnLoadMore="LoadMoreMessages"
                     OnThreadOpen="OpenThread"
                     OnReactionAdded="HandleReactionAdded"
                     OnMessageSent="SendMessage" />
    </div>
    @if (openThreadRootId.HasValue)
    {
        <div class="thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnReplySent="SendReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = new();
    private int? activeChannelId;
    private Channel? activeChannel;
    private List<Message> messages = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int? openThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private bool isLoading;
    private bool hasMoreMessages;
    private int pageSize = 50;
    private int currentSkip;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = new();
        currentSkip = 0;
        isLoading = true;
        CloseThreadState();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, pageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == pageSize;
        currentSkip = loaded.Count;
        ComputeThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        isLoading = false;
    }

    private async Task LoadMoreMessages()
    {
        if (isLoading || !activeChannelId.HasValue) return;
        isLoading = true;

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, currentSkip, pageSize);
        messages.InsertRange(0, older);
        currentSkip += older.Count;
        hasMoreMessages = older.Count == pageSize;
        ComputeThreadSummaries();

        isLoading = false;
    }

    private async Task OpenThread(int rootMessageId)
    {
        openThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        CloseThreadState();
    }

    private void CloseThreadState()
    {
        openThreadRootId = null;
        threadRootMessage = null;
        threadReplies = new();
    }

    private async Task SendMessage(string content)
    {
        if (!activeChannelId.HasValue) return;
        var msg = await ChatService.SendMessageAsync(activeChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task SendReply(string content)
    {
        if (!activeChannelId.HasValue || !openThreadRootId.HasValue) return;
        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, content, openThreadRootId.Value);
        threadReplies.Add(reply);

        // Update thread summary
        var rootId = openThreadRootId.Value;
        threadSummaries[rootId] = new ThreadSummary(rootId, threadReplies.Count, reply.SentAt);
    }

    private async Task HandleReactionAdded((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, new List<string> { "You" }));
            }
        }
    }

    private void ComputeThreadSummaries()
    {
        threadSummaries = new();
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }
}

.chat-page {
    display: grid;
    grid-template-columns: 250px 1fr;
    height: 100vh;
    overflow: hidden;
    transition: grid-template-columns 0.25s ease;
}

.chat-page.thread-open {
    grid-template-columns: 250px 1fr 320px;
}

.sidebar {
    overflow: hidden;
}

.main {
    overflow: hidden;
}

.thread {
    overflow: hidden;
}

